#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

vec2 uv2 = vUv;
uv2.x=1-uv2.x;

    vec2 d  = uTexSize.zw*4;
    vec2 d2 = uTexSize.zw*4;

    vec3 dx  = ( GetBlur1(vUv +vec2(1,0)*d )-GetBlur1(uv2-vec2(1,0)*d2) );
    vec3 dx2 = ( GetBlur1(uv2+vec2(1,0)*d2)-GetBlur1(vUv -vec2(0,1)*d ) );

    vec3 dy  = ( GetBlur1(uv2+vec2(0,1)*d2)-GetBlur1(vUv -vec2(1,0)*d ) );
    vec3 dy2 = ( GetBlur1(vUv +vec2(0,1)*d )-GetBlur1(uv2-vec2(0,1)*d2) );


vec2 uv_bg  = uv2 - vec2(dx2.y,dy2.y)*uTexSize.zw*16;
vec2 uv_bg2 = vUv  - vec2(dx.y ,dy.y )*uTexSize.zw*16;

        ret = (GetBlur2(uv_bg )-GetBlur1(uv_bg2)*1+GetPixel(uv_bg )*0.9 + (-dx.y  + dy.y )*0.4).y*0.8*vec3(1.0,1.1,1.2);
vec3 ret2 = (GetBlur2(uv_bg2)-GetBlur1(uv_bg )*1+GetPixel(uv_bg2)*0.9 + (-dx2.y + dy2.y)*0.4).y*0.8*vec3(1.2,1.0,1.1);

vec2 uv_m  = uv2 - vec2(dx2.x,dy.x )*uTexSize.zw*8;
vec2 uv_m2 = vUv  - vec2(dx.x ,dy2.x)*uTexSize.zw*8;

ret  = mix(ret , 2*vec3(0.0,0.5,1.0), GetBlur3(uv_m2 - vec2(dx2.y,dy.y )*0.4).x*0.4);
ret2 = mix(ret2, 2*vec3(0.5,1.0,0.0), GetBlur3(uv_m  - vec2(dx.y ,dy2.y)*0.4).x*0.4);

ret  = mix(ret , 2*vec3(0.5,1.0,1.0), GetBlur2(uv_m  - vec2(dx.y ,dy2.y)*0.2).x*0.4);
ret2 = mix(ret2, 2*vec3(1.0,0.5,1.0), GetBlur2(uv_m2 - vec2(dx2.y,dy.y )*0.2).x*0.4);

ret = mix(ret, 2*vec3(1,1,0.8), GetBlur1(uv_m - vec2(dx.y,dy.y)*0.1).x*0.2);
//ret = mix(ret, vec3(0.5,0,1), GetPixel(uv_m).x*0.4);

//ret = .7-ret2;
//ret2=.7-ret;
//ret-=ret2;
//MilkDrop3 Color Mode:
ret /= vec3(1.5,2.2,1.2);
//MilkDrop3 Brightness Mode:
ret *= 1.6;

  fragColor = ret;
}
